#!/usr/bin/env python3
"""Tests for authoritative XMage exact-scope splitting."""

from __future__ import annotations

import unittest

import xmage_authoritative_exact_scope_split as split


def queue_row(
    unit: str,
    *,
    effect_classes: list[str],
    card_id: str = "card-1",
    ability_kind: str = "one_shot",
    ability_classes: list[str] | None = None,
    xmage_signals: list[str] | None = None,
):
    return {
        "card_id": card_id,
        "card_name": "Fixture Spell",
        "normalized_name": "fixture spell",
        "translation_lane": "xmage_authoritative_adapter_required",
        "adapter_work_unit": unit,
        "effect_json": {"ability_kind": ability_kind},
        "xmage_effect_classes": effect_classes,
        "xmage_ability_classes": ability_classes or [],
        "xmage_signals": xmage_signals or [],
        "xmage_class": "FixtureSpell",
        "xmage_path": "/tmp/FixtureSpell.java",
    }


def metadata(
    name: str = "Fixture Spell",
    *,
    type_line: str = "Instant",
    oracle_text: str = "Draw two cards.",
    mana_cost: str = "",
):
    return {
        "card_id": "card-1",
        "name": name,
        "type_line": type_line,
        "oracle_text": oracle_text,
        "oracle_hash": split.md5_text(oracle_text),
        "mana_cost": mana_cost,
    }


class XMageAuthoritativeExactScopeSplitTest(unittest.TestCase):
    def test_creature_etb_life_gain_draw_maps_to_ordered_runtime_scope(self) -> None:
        row = queue_row(
            split.LIFE_UNIT,
            effect_classes=["DrawCardSourceControllerEffect", "GainLifeEffect"],
            ability_kind="triggered",
            ability_classes=["EntersBattlefieldTriggeredAbility", "FlyingAbility"],
            xmage_signals=["draw", "triggered_ability"],
        )
        proposal, reason = split.split_row(
            row,
            metadata(
                name="Inspiring Overseer",
                type_line="Creature - Angel Cleric",
                oracle_text="Flying\nWhen this creature enters, you gain 1 life and draw a card.",
            ),
            source_text="""
                this.addAbility(FlyingAbility.getInstance());
                Ability ability = new EntersBattlefieldTriggeredAbility(new GainLifeEffect(1));
                ability.addEffect(new DrawCardSourceControllerEffect(1).concatBy("and"));
                this.addAbility(ability);
            """,
        )

        self.assertEqual(reason, "selected_exact_scope")
        effect = proposal["effect_json"]
        self.assertEqual(effect["battle_model_scope"], split.ETB_LIFE_GAIN_DRAW_CREATURE_SCOPE)
        self.assertTrue(effect["etb_life_gain_draw"])
        self.assertEqual(effect["etb_life_gain_amount"], 1)
        self.assertEqual(effect["etb_draw_count"], 1)
        self.assertEqual(effect["resolution_order"], "gain_then_draw")
        self.assertEqual(effect["keywords"], ["flying"])

    def test_conditional_creature_etb_life_gain_draw_is_not_simple_scope(self) -> None:
        row = queue_row(
            split.LIFE_UNIT,
            effect_classes=["DrawCardSourceControllerEffect", "GainLifeEffect"],
            ability_kind="triggered",
            ability_classes=["EntersBattlefieldTriggeredAbility"],
            xmage_signals=["draw", "condition", "triggered_ability"],
        )

        self.assertFalse(split.is_creature_etb_life_gain_draw_unit(row))

    def test_fixed_boost_life_gain_spell_maps_to_composite_runtime_scope(self) -> None:
        row = queue_row(
            split.LIFE_UNIT,
            effect_classes=["BoostTargetEffect", "GainLifeEffect"],
        )
        proposal, reason = split.split_row(
            row,
            metadata(
                name="Moment of Craving",
                oracle_text="Target creature gets -2/-2 until end of turn. You gain 2 life.",
            ),
            source_text="""
                this.getSpellAbility().addEffect(new BoostTargetEffect(-2, -2, Duration.EndOfTurn));
                this.getSpellAbility().addTarget(new TargetCreaturePermanent());
                this.getSpellAbility().addEffect(new GainLifeEffect(2));
            """,
        )

        self.assertEqual(reason, "selected_exact_scope")
        effect = proposal["effect_json"]
        self.assertEqual(effect["battle_model_scope"], split.BOOST_LIFE_GAIN_SCOPE)
        self.assertEqual(effect["effect"], "composite_resolution")
        self.assertEqual(effect["power_delta"], -2)
        self.assertEqual(effect["toughness_delta"], -2)
        self.assertEqual(effect["life_gain_amount"], 2)
        self.assertEqual(effect["resolution_order"], "boost_then_gain")
        self.assertEqual(
            [component["effect"] for component in effect["_composite_rule_components"]],
            ["stat_modifier_until_eot", "life_total_change"],
        )

    def test_fixed_multi_target_boost_life_gain_spell_preserves_target_count(self) -> None:
        row = queue_row(
            split.LIFE_UNIT,
            effect_classes=["BoostTargetEffect", "GainLifeEffect"],
        )
        proposal, reason = split.split_row(
            row,
            metadata(
                name="Tandem Tactics",
                oracle_text="Up to two target creatures each get +1/+2 until end of turn. You gain 2 life.",
            ),
            source_text="""
                Effect effect = new BoostTargetEffect(1, 2, Duration.EndOfTurn);
                this.getSpellAbility().addEffect(effect);
                this.getSpellAbility().addTarget(new TargetCreaturePermanent(0, 2));
                this.getSpellAbility().addEffect(new GainLifeEffect(2));
            """,
        )

        self.assertEqual(reason, "selected_exact_scope")
        effect = proposal["effect_json"]
        self.assertEqual(effect["battle_model_scope"], split.BOOST_LIFE_GAIN_SCOPE)
        self.assertEqual(effect["target_count_min"], 0)
        self.assertEqual(effect["target_count_max"], 2)
        self.assertTrue(effect["up_to_count"])
        boost_component = effect["_composite_rule_components"][0]
        self.assertEqual(boost_component["target_count_min"], 0)
        self.assertEqual(boost_component["target_count_max"], 2)

    def test_dynamic_boost_life_gain_spell_stays_blocked(self) -> None:
        row = queue_row(
            split.LIFE_UNIT,
            effect_classes=["BoostTargetEffect", "GainLifeEffect"],
        )
        proposal, reason = split.split_row(
            row,
            metadata(
                name="Battle at the Bridge",
                oracle_text=(
                    "Improvise\nTarget creature gets -X/-X until end of turn. You gain X life."
                ),
            ),
            source_text="""
                DynamicValue xValue = GetXValue.instance;
                this.getSpellAbility().addEffect(new BoostTargetEffect(xValue, xValue, Duration.EndOfTurn));
                this.getSpellAbility().addEffect(new GainLifeEffect(GetXValue.instance));
                this.getSpellAbility().addTarget(new TargetCreaturePermanent());
            """,
        )

        self.assertIsNone(proposal)
        self.assertEqual(reason, "boost_life_gain_oracle_not_exact_fixed")

    def test_cycling_only_creature_maps_to_runtime_hand_cycling_scope(self) -> None:
        row = queue_row(
            "xmage_signature::no_effect_class::CyclingAbility::"
            "no_target_class::no_condition_class::no_signal",
            effect_classes=[],
            ability_kind="static",
            ability_classes=["CyclingAbility"],
        )
        proposal, reason = split.split_row(
            row,
            metadata(
                name="Barkhide Mauler",
                type_line="Creature - Beast",
                oracle_text="Cycling {2} ({2}, Discard this card: Draw a card.)",
            ),
            source_text='this.addAbility(new CyclingAbility(new GenericManaCost(2)));',
        )

        self.assertEqual(reason, "selected_exact_scope")
        effect = proposal["effect_json"]
        self.assertEqual(effect["battle_model_scope"], split.CYCLING_ONLY_SCOPE)
        self.assertEqual(effect["effect"], "creature")
        self.assertEqual(effect["cycling_cost"], "{2}")
        self.assertEqual(effect["cycling_status"], "runtime_executor_v1")
        self.assertTrue(effect["has_cycling"])

    def test_cycling_only_creature_preserves_static_keywords(self) -> None:
        row = queue_row(
            "xmage_signature::no_effect_class::CyclingAbility,FlyingAbility::"
            "no_target_class::no_condition_class::no_signal",
            effect_classes=[],
            ability_kind="static",
            ability_classes=["CyclingAbility", "FlyingAbility"],
        )
        proposal, reason = split.split_row(
            row,
            metadata(
                name="Keeneye Aven",
                type_line="Creature - Bird Soldier",
                oracle_text="Flying\nCycling {2} ({2}, Discard this card: Draw a card.)",
            ),
            source_text=(
                "this.addAbility(FlyingAbility.getInstance());"
                "this.addAbility(new CyclingAbility(new ManaCostsImpl<>(\"{2}\")));"
            ),
        )

        self.assertEqual(reason, "selected_exact_scope")
        effect = proposal["effect_json"]
        self.assertEqual(effect["battle_model_scope"], split.CYCLING_ONLY_SCOPE)
        self.assertEqual(effect["keywords"], ["flying"])
        self.assertTrue(effect["flying"])
        self.assertEqual(effect["cycling_cost"], "{2}")

    def test_prowess_creature_maps_to_noncreature_spell_trigger_scope(self) -> None:
        row = queue_row(
            "xmage_signature::no_effect_class::FlyingAbility,ProwessAbility::"
            "no_target_class::no_condition_class::no_signal",
            effect_classes=[],
            ability_kind="static",
            ability_classes=["FlyingAbility", "ProwessAbility"],
        )
        proposal, reason = split.split_row(
            row,
            metadata(
                name="Jeskai Windscout",
                type_line="Creature - Bird Scout",
                oracle_text="Flying\nProwess",
            ),
            source_text="""
                this.addAbility(FlyingAbility.getInstance());
                this.addAbility(new ProwessAbility());
            """,
        )

        self.assertEqual(reason, "selected_exact_scope")
        effect = proposal["effect_json"]
        self.assertEqual(effect["battle_model_scope"], split.PROWESS_CREATURE_SCOPE)
        self.assertEqual(effect["trigger"], "noncreature_spell_cast")
        self.assertEqual(effect["trigger_effect"], "boost_source_until_eot")
        self.assertEqual(effect["trigger_power_bonus_until_eot"], 1)
        self.assertEqual(effect["trigger_toughness_bonus_until_eot"], 1)
        self.assertEqual(effect["keywords"], ["flying", "prowess"])
        self.assertTrue(effect["prowess"])
        self.assertTrue(effect["flying"])

    def test_changeling_creature_maps_to_all_creature_types_scope(self) -> None:
        row = queue_row(
            "xmage_signature::no_effect_class::ChangelingAbility,FlyingAbility::"
            "no_target_class::no_condition_class::no_signal",
            effect_classes=[],
            ability_kind="static",
            ability_classes=["ChangelingAbility", "FlyingAbility"],
        )
        proposal, reason = split.split_row(
            row,
            metadata(
                name="Avian Changeling",
                type_line="Creature - Shapeshifter",
                oracle_text="Changeling (This card is every creature type.)\nFlying",
            ),
            source_text="""
                this.addAbility(ChangelingAbility.getInstance());
                this.addAbility(FlyingAbility.getInstance());
            """,
        )

        self.assertEqual(reason, "selected_exact_scope")
        effect = proposal["effect_json"]
        self.assertEqual(effect["battle_model_scope"], split.CHANGELING_CREATURE_SCOPE)
        self.assertEqual(effect["keywords"], ["changeling", "flying"])
        self.assertTrue(effect["changeling"])
        self.assertTrue(effect["all_creature_types"])
        self.assertTrue(effect["universal_creature_subtypes"])
        self.assertTrue(effect["_keywords_are_self"])
        self.assertTrue(effect["flying"])

