        self.assertEqual(
            effect["target_constraints"]["any_of"],
            [
                {"stack_object": "spell", "counter_target_mana_value_max": 2},
                {
                    "stack_object": "spell",
                    "spell_colors": ["R", "G"],
                    "counter_target_mana_value_max": 6,
                },
            ],
        )

